diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..ce3571f28742 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1906,6 +1906,39 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(X+C2) --> (C-C2)-X
     if (match(Op1, m_Add(m_Value(X), m_ImmConstant(C2))))
       return BinaryOperator::CreateSub(ConstantExpr::getSub(C, C2), X);
+
+    // C3 - ((C1 -nuw x) & C2) --> and x, (C3 | (~C2 << ctz(C2)))
+    // where C3 == (C1 & C2), (C1 & ~C2) < (~C2 + 1), and -C2 is a power of 2.
+    // The last condition ensures C2 is of the form 0b111...000.
+    Instruction *AndI;
+    const APInt *C2Int;
+    if (match(Op1, m_And(m_OneUse(m_Instruction(AndI)), m_APInt(C2Int)))) {
+      if (AndI->getOpcode() == Instruction::Sub && AndI->hasNoUnsignedWrap()) {
+        if (ConstantInt *C1 = dyn_cast<ConstantInt>(AndI->getOperand(0))) {
+          Value *X = AndI->getOperand(1);
+          if (ConstantInt *CI = dyn_cast<ConstantInt>(C)) {
+            const APInt &C3 = CI->getValue();
+            const APInt &C1V = C1->getValue();
+            APInt NotC2 = ~(*C2Int);
+            // Check C3 == (C1 & C2)
+            if ((C1V & *C2Int) == C3) {
+              // Check if -C2 is a power of 2 (i.e., C2 = -2^k)
+              APInt NegC2 = -(*C2Int);
+              if (NegC2.isPowerOf2()) {
+                // Check (C1 & ~C2) < (~C2 + 1)
+                APInt LowMask = NotC2 + 1;
+                if ((C1V & NotC2).ult(LowMask)) {
+                  // Compute mask: C3 | (~C2 << ctz(C2))
+                  unsigned TrailingZeros = C2Int->countTrailingZeros();
+                  APInt NewMask = C3 | (NotC2 << TrailingZeros);
+                  return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), NewMask));
+                }
+              }
+            }
+          }
+        }
+      }
+    }
   }

   auto TryToNarrowDeduceFlags = [this, &I, &Op0, &Op1]() -> Instruction * {
